import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';

@Component({
  tag: 'feature-card-component',
  styleUrl: 'feature-card-component.css',
  shadow: true,
})
export class FeatureCardComponent {
  @Event() featureButtonClicked: EventEmitter<void>;

  @Prop() btntitle: string = 'Take the quiz';
  @Prop() quiztitle: string = 'How much do you know about sleep apnea?';
  @Prop() quizdescription: string = 'Take this quick quiz to learn more about sleep apnea and feel empowered to talk to a provider if you are experiencing symptoms.';
  @Prop() buttonAriaLabel: string = 'Click to take the quiz';
  @Prop() buttonEvents: { [key: string]: (event: Event) => void } = {};
  @Prop() isMounted: boolean = true;

  private handleButtonClick = () => {
    this.featureButtonClicked.emit();
  };

  render() {
    return (
      <div class="bgr-white overflow-hidden" style={{ display: this.isMounted ? 'block' : 'none' }}>
        <section class="container-lg mx-auto" aria-label={this.quiztitle}>
          <div class="rounded-5 bgr-neutral-stone feature-card-container" aria-label="">
            <div class="d-flex feature-card-content">
              <div class="d-flex feature-card-content__left">
                <div class="feature-card-content__left__sub___content">
                  <h2 class="feature-card-content__left___header">{this.quiztitle}</h2>
                </div>
                <div class="feature-card-content__left__paragraph">
                  <p>{this.quizdescription}</p>
                </div>
                <div class="feature-card-btn__container">
                  <button-component label={this.buttonAriaLabel} onBtnClick={this.handleButtonClick}>
                    {this.btntitle}
                  </button-component>
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
